            PyObject *val = PyList_GetItem(row, j);
            cov[i * n + j] = PyFloat_AsDouble(val);
            if (cov[i * n + j] == -1.0 && PyErr_Occurred()) {
                free(weights);
                free(cov);
                return NULL;
            }
        }
    }

    // Allocate temp array for S * x
    double *temp = (double *)malloc(n * sizeof(double));
    if (!temp) {
        free(weights);
        free(cov);
        PyErr_SetString(PyExc_MemoryError, "Failed to allocate temp array");
        return NULL;
    }

    // Step 1: Compute S * x: temp[i] = sum_j cov[i][j] * weights[j]
    for (Py_ssize_t i = 0; i < n; i++) {
        double row_sum = 0.0;
        const double *cov_row = cov + i * n;
        for (Py_ssize_t j = 0; j < n; j++) {
            row_sum += cov_row[j] * weights[j];
        }
        temp[i] = row_sum;
    }

    // Step 2: Compute x^T * temp: risk_squared = sum_i weights[i] * temp[i]
    double risk_squared = 0.0;
    for (Py_ssize_t i = 0; i < n; i++) {
        risk_squared += weights[i] * temp[i];
    }

    free(weights);
    free(cov);
    free(temp);

    return PyFloat_FromDouble(sqrt(risk_squared));
}

static PyObject* portfolio_return_c(PyObject *self, PyObject *args) {
    PyObject *weights_list, *returns_list;

    if (!PyArg_ParseTuple(args, "OO", &weights_list, &returns_list))
        return NULL;

    Py_ssize_t n = PyList_Size(weights_list);

